DO $$
DECLARE
    db_exists BOOLEAN;
BEGIN
    -- Check if the table exists
    SELECT EXISTS (
        SELECT 1 
        FROM information_schema.tables 
        WHERE table_schema = 'nba' -- Ensure this matches your actual schema
        AND table_name = 'player'
    ) INTO db_exists;

    IF db_exists THEN
        -- Insert Data
        ON CONFLICT (playerid) DO NOTHING; -- Recommended to prevent errors on duplicate runs
    END IF;
END $$;